INSERT INTO `institusis` (`id`, `kod_institusi`, `nama_institusi`, `jenis_institusi`, `gambar_institusi`, `alamat`, `mengenai_institusi`, `created_at`, `updated_at`) VALUES
(1, 'C-21-G', 'KOLEJ DAYATECH', 'TVET', 'images/institusi/kolej-dayatech-1775609988.webp', 'Pusat Komersial Arena Bintang, C21-G,1,2 Jalan Zuhal U5/179, Seksyen U5, 40150 Shah Alam, Selangor', 'Pusat Latihan Kemahiran bertauliah yang mengkhusus dalam bidang teknikal dan kejuruteraan. Menawarkan program Sijil Kemahiran Malaysia (SKM) yang berorientasikan latihan amali bagi melahirkan tenaga kerja mahir yang kompeten, profesional dan memenuhi kehendak industri masa kini.', '2026-04-07 08:59:48', '2026-04-07 14:22:16'),
(2, '78000', 'KOLEJ TEKNIKAL BUMIPUTERA (KTEB)', 'TVET', 'images/institusi/kolej-teknikal-bumiputera-kteb-1775620045.jpeg', 'Wisma Umno, Jalan Anggerik 2, Taman Seri Bayu 2, 78000 Alor Gajah, Melaka', 'Penubuhan kolej ini telah diluluskan oleh Menteri Pendidikan sebagai Institusi Pendidikan Tinggi Swasta (IPTS) pada 11 Julai 1997 dengan nama “INSTITUT YAYASAN ALOR GAJAH”. Ia juga didaftarkan dengan Pendaftar Sekolah Melaka pada 29 September 1997. Dengan pengembangan dan penambahan peralatan dan kakitangan pengajar, “INSTITUT YAYASAN MELAKA” secara rasmi ditukar nama kepada “KOLEJ TEKNOLOGI YAYASAN ALOR GAJAH” pada 11 Mei 2002 yang dikenali sebagai KT-YAGA. KT-YAGA kemudian diambil alih pada akhir 2009 oleh nama terkenal dalam sektor pendidikan tinggi, KN Education Sdn. Bhd. Pelbagai penambahbaikan dan reformasi dicapai di bawah pengurusan ini, dan dinamakan semula sebagai institusi Kolej Teknologi Unifield yang diluluskan oleh Kementerian Pendidikan Tinggi pada 06 Januari 2011. Selaras dengan visi, satu penjenamaan semula dilakukan dan diluluskan secara rasmi pada 11 Mac 2013 dan kolej ini kini dikenali sebagai UNIFIELD INTERNATIONAL COLLEGE (UIC)', '2026-04-07 11:47:25', '2026-04-07 14:31:26'),
(3, '71700', 'KOLEJ TEKNIKAL IBNU SINA (KTIB)', 'TVET', 'images/institusi/kolej-teknikal-bumiputera-kteb-1775627125.webp', 'Lot 27, Jalan Kaunselor 2, College Heights Garden Resort,\r\n71700 Pajam Mantin, Negeri Sembilan', 'Penubuhan kolej ini telah diluluskan oleh Menteri Pendidikan sebagai Institusi Pendidikan Tinggi Swasta (IPTS) pada 11 Julai 1997 dengan nama “INSTITUT YAYASAN ALOR GAJAH”. Ia juga didaftarkan dengan Pendaftar Sekolah Melaka pada 29 September 1997. Dengan pengembangan dan penambahan peralatan dan kakitangan pengajar, “INSTITUT YAYASAN MELAKA” secara rasmi dinamakan semula sebagai “KOLEJ TEKNOLOGI YAYASAN ALOR GAJAH” pada 11 Mei 2002 yang dikenali sebagai KT-YAGA. KT-YAGA kemudian diambil alih pada akhir 2009 oleh nama terkenal dalam sektor pendidikan tinggi, KN Education Sdn. Bhd. Pelbagai penambahbaikan dan pembaharuan dicapai di bawah pengurusan ini, dan dinamakan semula sebagai institusi Kolej Teknologi Unifield yang diluluskan oleh Kementerian Pendidikan Tinggi pada 06 Januari 2011. Selaras dengan visi, satu penjenamaan semula dilakukan dan diluluskan secara rasmi pada 11 Mac 2013 dan kini kolej ini dikenali sebagai UNIFIELD INTERNATIONAL COLLEGE (UIC).', '2026-04-07 13:45:25', '2026-04-09 09:43:16'),
(4, '47160', 'SILVERSPOON INTERNATIONAL COLLEGE', 'TVET', 'images/institusi/silverspoon-international-college-1775628370.jpg', '12 & 12A, Jalan OP1/3, Pusat Perdagangan One Puchong, Off, Jalan Puchong, Bandar Puchong Jaya, 47160 Puchong, Selangor, Malaysia', 'Silverspoon International College (SSiC) telah ditubuhkan pada 2010 dengan objektif untuk menyediakan latihan vokasional yang mantap dalam kursus Seni Kulinari dan Pastri seperti yang diluluskan oleh Jabatan Pembangunan Kemahiran (JPK) di bawah Kementerian Sumber Manusia, Malaysia. Kolej Antarabangsa Silverspoon (SSiC) percaya bahawa pengalaman industri sebenar adalah bahagian penting dalam pendidikan hospitaliti. Pelajar akan berpeluang menjalani praktikum atau Koperasi di pelbagai hotel, restoran, katering syarikat penerbangan, dan lain-lain, yang diatur secara eksklusif oleh SSiC apabila permintaan meningkat untuk graduan baru untuk mengisi pelbagai jawatan dan bekerja dengan jayanya melalui pangkat.', '2026-04-07 13:58:56', '2026-04-07 14:36:57'),
(5, 'L01143', 'NOBLE SCHOOL ENGINEERING', 'TVET', 'images/institusi/noble-school-engineering-1775629028.webp', '36 Mb2, Kampus Kejuruteraan Noble Taman Medan Bersatu 34000 Taiping, Perak', 'Noble TVET adalah merupakan kumpulan dua (2) ILKS yang telah disatukan bagi mewujudkan satu reformasi latihan berkonsepkan Industri untuk mempertingkatkan jumlah tenaga kerja terlatih di dalam IKS tempatan. Terletak di bandar Taiping – sebuah Bandar Warisan tinggalan 33 sejarah awal pembangunan Tanah Melayu sejak tahun 1800 yang dikenali sebagai ‘The Rain Town of Malaysia’ dan merupakan pemenang tempat Ke-3 Anugerah 100 Destinasi Lestari Terbaik Dunia Di International Tourismus-Borse (ITB) Berlin, Germany 2018. Dan pada 16 Disember 2022 Taiping sekali lagi telah menerima Anugerah Destinasi Rekreasi Terbaik Industri Pelancongan Malaysia 2022 (Malaysia Tourism Industry Award 2022).', '2026-04-07 14:17:08', '2026-04-07 14:17:08'),
(6, 'L02138', 'NOBLE SCHOOL CITY CAMPUS', 'TVET', 'images/institusi/noble-school-city-campus-1775631090.jpg', '33, Jalan TBC 3, Taiping Business Centre, 34000 Taiping, Perak.', 'Noble TVET adalah merupakan kumpulan dua (2) ILKS yang telah disatukan bagi mewujudkan satu reformasi latihan berkonsepkan Industri untuk mempertingkatkan jumlah tenaga kerja terlatih di dalam IKS tempatan. Terletak di bandar Taiping – sebuah Bandar Warisan tinggalan 33 sejarah awal pembangunan Tanah Melayu sejak tahun 1800 yang dikenali sebagai ‘The Rain Town of Malaysia’ dan merupakan pemenang tempat Ke-3 Anugerah 100 Destinasi Lestari Terbaik Dunia Di International Tourismus-Borse (ITB) Berlin, Germany 2018. Dan pada 16 Disember 2022 Taiping sekali lagi telah menerima Anugerah Destinasi Rekreasi Terbaik Industri Pelancongan Malaysia 2022 (Malaysia Tourism Industry Award 2022).', '2026-04-07 14:51:30', '2026-04-07 14:51:30'),
(7, '42000', 'WORKERS INSTITUTE TECHNOLOGY', 'TVET', 'images/institusi/workers-insritute-technology-1775632540.jpg', 'Jalan Banting, Off Jalan Pandamaran, 42000 Port Klang, Selangor, Malaysia.', 'Kolej WIT sebelum ini dikenali sebagai Workers Institute of Technology, kolej kejuruteraan dan latihan teknikal berasaskan Pembangunan Sumber Manusia di Malaysia. Objektif utama WIT adalah untuk menyediakan pengajian kejuruteraan, latihan vokasional dan kemahiran teknikal yang akan membolehkan pelajar untuk maju dalam kehidupan dan membantu usaha kerajaan Malaysia dalam mencapai matlamat tinggi untuk menjadikan Malaysia sebuah negara maju menjelang tahun 2020. WIT merupakan ilham dua orang sahabat setia, Dr. V. David dan Tan Sri Zainal Rampak, daripada Kesatuan Pekerja Pengangkutan Malaysia (TWU) yang dibina pada tahun 1977 di atas 10.4 ekar tanah yang terletak di Kawasan Industri Pandamaran (Pandamaran, Klang Selangor) diatas sebidang tanah yang diberikan oleh Kerajaan Negeri Selangor dibawah kepimpinan Allahyarham Dato\' Seri Harun bin Haji Idris, Menteri Besar Selangor pada waktu itu dengan premium yang paling rendah, dikelilingi oleh perumahan, lebuh raya, pembangunan moden, kawasan perindustrian bagi memenuhi permintaan yang semakin meningkat bagi latihan teknikal untuk lepasan sekolah & komuniti korporat.', '2026-04-07 15:15:40', '2026-06-10 19:25:48'),
(8, 'L02238', 'AZMIDA TECHNICAL COLLEGE', 'TVET', 'images/institusi/azmida-technical-college-1775633722.webp', 'Lot 16988, Jalan 2, Kawasan Industri Taman Selayang Baru, 68100 Batu Caves, Selangor, Malaysia', 'Azmida Technical College (L02238) merupakan sebuah Pusat Bertauliah yang diberi pentauliahan oleh pihak Jabatan Pembangunan Kemahiran (JPK) Kementerian Sumber Manusia Malaysia pada 28 Jun 2011. Pada tahun 2017 Pusat Bertauliah ini telah mendapat pengiktirafan sebagai sebuah Kolej Latihan Kemahiran yang menyediakan latihan berkonsepkan Latihan Teknikal & Pendidikan Vokasional (TVET) dan ditukar nama sebagai Azmida Technical College (L02238).', '2026-04-07 15:35:22', '2026-04-07 15:35:22'),
(10, 'L02080', 'AF TVET ACADEMY', 'TVET', 'images/institusi/af-tvet-academy-1775636197.jpg', 'Jalan Putra 2, Taman Kajang Putra, 43000 Kajang, Selangor', 'Pusat Latihan Kemahiran TVET bertauliah yang menawarkan program latihan industri, Sijil Kemahiran & kursus pendek. Melahirkan tenaga mahir, berdaya saing dan diiktiraf.', '2026-04-07 16:16:37', '2026-05-05 20:28:24'),
(11, '144465-D', 'FUTURE EDGE COLLEGE', 'TVET', 'images/institusi/future-edge-college-1775636788.jpg', 'No. B2-01, Jalan Teknologi 2/1D, PJU 5, Kota Damansara, 47810 Petaling Jaya, Selangor Darul Ehsan, Malaysia', 'Kolej FutureEdge adalah pintu masuk anda kepada program TVET berasaskan kemahiran yang praktikal. Pendekatan kami yang bersifat hands-on membekalkan anda dengan kepakaran yang diperlukan untuk kerjaya yang tinggi permintaan, memastikan anda bersedia bekerja dari hari pertama', '2026-04-07 16:26:28', '2026-05-05 20:29:36'),
(12, '53100', 'S.T.I COLLEGE MALAYSIA', 'TVET', 'images/institusi/sti-college-malaysia-1775637778.jpg', '243-A, 243-B, & 243C,\r\nJalan Bandar 13, Taman Melawati,\r\n53100 Kuala Lumpur, W. P. Kuala Lumpur, Malaysia.', 'Pusat Latihan Kemahiran bertauliah yang mengkhusus dalam bidang teknikal dan kejuruteraan. Menawarkan program Sijil Kemahiran Malaysia (SKM) yang berorientasikan latihan amali bagi melahirkan tenaga kerja mahir yang kompeten, profesional dan memenuhi kehendak industri masa kini.', '2026-04-07 16:41:44', '2026-04-07 16:42:58'),
(13, 'L02882', 'TITAN SKILL COLLEGE', 'TVET', 'images/institusi/titan-skill-college-1778113729.png', '6, Jln Perusahaan Amari, Kuala Lumpur, Malaysia', 'Pusat Bertauliah Jabatan Pembangunan Kemahiran (JPK)', '2026-04-07 20:06:37', '2026-05-06 08:28:49'),
(14, 'L02163', 'JV SKILL TRAINING CENTRE', 'TVET', 'images/institusi/jv-skill-training-centre-1775650435.jpg', 'No 6-01,6-02,6-03,8-01,10-01 Jalan Pandan Ria 4, Pusat Perdagangan Pandan, 81100 Johor Bahru Premis Tambahan: No.6, Jalan Sri Purnama 2/1 Kangkar Tebrau 81100 Johor Bahru,', 'Pusat Latihan Kemahiran JV ditubuhkan pada 22 Ogos 2009 dengan kurikulum yang relevan dengan industri berdasarkan pembelajaran berasaskan pengalaman bagi menghasilkan graduan yang berkemahiran dan berkelayakan yang memenuhi keperluan industri. JV Skill adalah pusat bertauliah di bawah Jabatan Pembangunan Kemahiran (DSD) di bawah Kementerian Sumber Manusia, Malaysia. Pada Julai 2013, Kolej JV Skill telah diberi penarafan 5-Bintang oleh Jabatan Pembangunan Kemahiran (DSD) di bawah Kementerian Sumber Manusia, Malaysia.', '2026-04-07 20:13:55', '2026-04-07 20:14:58'),
(15, '70300', 'AMBITIOUS ACADEMY', 'TVET', 'images/institusi/ambitious-academy-1775650876.jpeg', 'No. 648-654, Jalan Haruan 4/9, Oakland Commercial Center, 70300 Seremban, Negeri Sembilan.', 'Ambitious Infinite Resources Sdn.Bhd. (AIRSB) mula beroperasi di Setia Tropika, Johor Bahru pada Januari 2014, yang bepindah ke Wisma HYH yang terletak di pusat bandar Johor Bahru pada September 2014. Ambitious Academy Sdn. Bhd. (AASB) kemudiannya mengikuti operasi pertamanya di bangunan yang sama pada Februari 2015. Ambitious Education Group selama bertahun-tahun telah membina reputasi dan rekod pretasi yang boleh dipercayai dalam pelbagai perniagaan yang dikendalikannya. Ini termasuk pendidikan dan latihan, pembangunan kemahiran, perkongsian belajar-kerja, perkhidmatan pengambilan, penyumberan strategik untuk pengurusan tenaga kerja luar jangka dan perundingan. Ia ditugaskan dengan tujuan khusus untuk memenuhi permintaan yang semakin meningkat untuk profesional terlatih dalam masakan, syarikat penerbangan, pelayaran, hotel dan industri lain yang berkaitan. Pada masa ini terletak di bangunan dua setengah tingkat di Skudai Johor Bahru, AIRSB menawarkan kemudahan moden dengan kemudahan seni terkini untuk pelajarnya, menggabungkan ke dalam persekitaran semula jadi dan luas. Dengan Pejabat Pendtadbiran Korporatnya di Seremban, Negeri Sembilan, ia telah melangkah jauh, muncul sebagai salah satu pesaing utama untuk kecemerlangan masakan, hospitaliti, perniagaan dan penerbangan.', '2026-04-07 20:21:16', '2026-04-07 20:21:16'),
(16, 'P13A-1', 'MALAYSIA TECHNICAL SKILL ACADEMY (MTSA) TEMERLOH', 'TVET', 'images/institusi/malaysia-technical-skill-academy-mtsa-temerloh-1778070955.webp', 'Termeloh, Pahang', 'Adalah sebuah pusat penyediaan latihan yang memfokuskan kepada bidang kemahiran sebagai teras yang mengikut arus perdana kini. Kami percaya dengan latihan berkualiti tinggi dan kemahiran profesional yang diterapkan oleh para pengajar di kolej MTSA Karak, para pelajar bukan sahaja dapat meningkatkan jati diri, tetapi juga dapat membangunkan modal insan, samada dalam bidang pendidikan atau bidang pekerjaan. “Kami memberi jaminan masa depan yang lebih baik dengan kemahiran yang lebih baik”!', '2026-04-07 20:28:08', '2026-05-06 09:40:49'),
(17, '28600', 'MALAYSIA TECHNICAL SKILL ACADEMY (MTSA) KARAK', 'TVET', 'images/institusi/malaysia-technical-skill-academy-mtsa-karak-1775651678.webp', 'No. P13A-1, 1, Jalan Lama Bentong - Karak, 28600 Karak, Pahang, Malaysia', 'Adalah sebuah pusat penyediaan latihan yang memfokuskan kepada bidang kemahiran sebagai teras yang mengikut arus perdana kini. Kami percaya dengan latihan berkualiti tinggi dan kemahiran profesional yang diterapkan oleh para pengajar di kolej MTSA Karak, para pelajar bukan sahaja dapat meningkatkan jati diri, tetapi juga dapat membangunkan modal insan, samada dalam bidang pendidikan atau bidang pekerjaan. “Kami memberi jaminan masa depan yang lebih baik dengan kemahiran yang lebih baik”!', '2026-04-07 20:34:38', '2026-04-07 20:34:38'),
(18, 'P13A', 'MALAYSIA TECHNICAL SKILL ACADEMY (MTSA) BENTONG', 'TVET', 'images/institusi/malaysia-technical-skill-academy-mtsa-bentong-1775652498.webp', 'P2-12 JALAN MEDANG LESTARI TAMAN MEDANG LESTARI 28700 BENTONG, PAHANG', 'Adalah sebuah pusat penyediaan latihan yang memfokuskan kepada bidang kemahiran sebagai teras yang mengikut arus perdana kini. Kami percaya dengan latihan berkualiti tinggi dan kemahiran profesional yang diterapkan oleh para pengajar di kolej MTSA Karak, para pelajar bukan sahaja dapat meningkatkan jati diri, tetapi juga dapat membangunkan modal insan, samada dalam bidang pendidikan atau bidang pekerjaan. “Kami memberi jaminan masa depan yang lebih baik dengan kemahiran yang lebih baik”!', '2026-04-07 20:48:18', '2026-05-06 09:41:37'),
(19, 'L02054', 'DUAL TRAINING INSTITUTE (DTI)', 'TVET', 'images/institusi/dual-training-institute-dti-1775653038.webp', 'Lot 158 Jalan S2b3 Green Technology Park Seremban 2 70300 Seremban Negeri Sembilan', 'Institut Latihan Dual adalah sebuah institusi pendidikan yang menggabungkan pengetahuan teori dengan latihan praktikal.', '2026-04-07 20:57:18', '2026-05-05 20:37:15'),
(20, 'TP-060-3:2013', 'MEATECH COLLEGE', 'TVET', 'images/institusi/meatech-college-1775653602.jpg', 'L2-11 & L2-12, Tingkat 2, Tower B (Begonia), Youth City Residence, Vision City, Persiaran Pusat Bandar, Bandar Baru Nilai 71800 Nilai Negeri Sembilan', 'Bermula 2002 apabila kumpulan meraka dimulakan sebagai Approved Training Provider (ATP) yang diiktiraf oleh Jabatan Pembangunan Kemahiran (DSD), Kementerian Sumber Manusia Malaysia. - Selama bertahun-tahun, Syarikat ini telah melaksanakan banyak projek yang mencabar dan kemahiran terkumpul, pengetahuan dan pengalaman dalam TVET. - Mereka telah melatih sejumlah besar mekanik, pengendali dan juruteknik yang telah memberikan sumbangan besar kepada industri dan kejayaan ekonomi syarikat. - Ogos 2011, Meatech ATC Sdn. Bhd. (MATC) telah diperbadankan, memberi tumpuan terutamanya kepada penyediaan latihan TVET dalam program latihan berkaitan penerbangan. - Pada 2015, MEATECH ATC Sdn. Bhd. menandatangani Memorandum Persefahaman (MoU) dengan Pusat Latihan Penerbangan AERO-Bildung, dan institusi pendidikan yang berpangkalan di Jerman dalam membangunkan kursus latihan pensijilan profesional yang diiktiraf oleh Agensi Keselamatan Penerbangan Eropah (EASA). - Tujuan mereka ialah melahirkan kakitangan pesawat yang berkemahiran tinggi dengan keupayaan untuk melakukan pelbagai aktiviti penyelenggaraan. - Mereka menawarkan 2 program iaitu “AVIATION – AIRCRAFT MAINTENANCE TRAINING” dan “AVIATION – IN-FLIGHT CABIN SERVICES”', '2026-04-07 21:06:42', '2026-04-07 21:06:42'),
(21, '47650', 'MYBUSINESS ACADEMY', 'TVET', 'images/institusi/mybusiness-academy-1775654201.jpg', '2 Jalan Putra Mahkota 7/7A 47650 Subang Jaya Selangor', 'Memberi peluang dan laluan kerjaya bagi calon bekerja dan menimba pengalaman dalam industri. - Melaksanakan pantauan pihak akademi bagi penuhi kelayakan (SKM 3) & (DKM) ikut tempoh pengiktirafan pengalaman terdahulu mengikut kod program yang dipilih. - Jurus ke arah kemahiran profesional & releven kepada industry dengan bekalkan calon kepada industry mengikut kod program bersesuaian. - Jalankan kerjasama dengan COLLEGE OF BIRMINGHAM, UNITED KINGDOM. Berasaskan kemahiran & Pembangunan profesional. - MBA merupakan sebuah pusat bertauliah yang berdaftar dengan Jabatan Pembangunan Kemahiran serta melakukan program aperantis.', '2026-04-07 21:16:41', '2026-05-05 20:38:18'),
(22, 'L02723', 'ACADEMY ADELPHI WORLDWIDE', 'TVET', 'images/institusi/academy-adelphi-worldwide-1775654681.jpg', 'No 31, Jalan Durian Emas 4, Betaria Business Centre,701 00 Seremban, Negeri Sembilan', 'Academy Adelphi Worldwide Hotels Sdn Bhd (Seremban) ialah cawangan kedua selepas cawangan Skudai JB, menawarkan kursus Seni Kulinari, Automotif, Pendidikan Awal Kanak-Kanak, Pengurusan Pejabat dan Pastri yang direka untuk menampung pelajar daripada keluarga berpendapatan rendah melalui Jabatan Pembangunan Kemahiran.', '2026-04-07 21:24:41', '2026-05-05 20:38:42'),
(23, 'L02313', 'UNIFIELD INTERNATIONAL COLLEGE (UIC) (PROGRAM DALAMAN)', 'Diploma', 'images/institusi/unifield-international-college-uic-1775618872.webp', 'Lot 25 Jalan Kaunselor, College Heights Garden Resort, 71700 Mantin, Negeri Sembilan', 'Unifield International College (UIC) merupakan sebuah institusi pengajian tinggi yang menawarkan pelbagai program akademik dan kemahiran bagi melahirkan graduan yang profesional dan berdaya saing. Bagi meningkatkan kualiti pendidikan, UIC turut menjalinkan Program Kerjasama Diploma dengan beberapa universiti tempatan seperti Universiti Malaya (UM), Universiti Teknologi Malaysia (UTM) dan Universiti Teknologi MARA (UITM). Melalui program kerjasama ini, pelajar berpeluang mengikuti pengajian diploma dengan pendidikan yang lebih berkualiti, pendedahan akademik yang luas serta pembelajaran yang relevan dengan keperluan industri semasa.', '2026-04-07 09:01:47', '2026-05-21 19:35:16'),
(24, '05', 'UNIVERSITI TEKNOLOGI MALAYSIA (PROGRAM USAHASAMA)', 'Diploma', 'images/institusi/universiti-teknologi-malaysia-1775619641.jpg', 'Lot 25 Jalan Kaunselor, College Heights Garden Resort, 71700 Mantin, Negeri Sembilan', 'Pusat Kerjasama UTM merujuk kepada inisiatif di bawah Sekolah Pendidikan Profesional Dan Pendidikan Berterusan (UTMSPACE) yang menawarkan program pengajian separuh masa (seperti Diploma) melalui kerjasama dengan institusi kolej swasta terpilih, bertujuan meluaskan akses pendidikan sepanjang hayat.\r\n\r\nInstitusi Pengajian Tinggi yang diberi kebenaran menjalankan program akademik Universiti Teknologi Malaysia (UTM) bertanggungjawab sepenuhnya terhadap pengurusan program di premis masing-masing, termasuk tenaga pengajar, infrastruktur, peralatan pembelajaran serta kebajikan pelajar. Konvokesyen bagi program diploma dan ijazah kerjasama pula dikendalikan sepenuhnya oleh UTM di kampus Skudai.', '2026-04-07 11:40:41', '2026-05-18 15:18:17'),
(25, 'UE4344001', 'UNIVERSITI TEKNOLOGI MARA (UITM) ( PROGRAM USAHASAMA)', 'Diploma', 'images/institusi/universiti-teknologi-mara-uitm-1775620480.jpg', 'Lot 25 Jalan Kaunselor, College Heights Garden Resort, 71700 Mantin, Negeri Sembilan', 'Program Usahasama antara UiTM telah bermula sejak tahun 1996, bermula dengan hanya sebuah kolej Bersekutu, jalinan usahasama pada masa kini telah berkembang, meliputi pertambahan bilangan kolej, peningkatan enrolmen, serta pengembangan bilangan program akademik terdiri daripada Pra Diploma dan Diploma dalam bidang Sains dan Teknologi, Perniagaan dan Pengurusan serta Sains Sosial dan Kemasyarakatan.', '2026-04-07 11:54:40', '2026-05-21 19:48:21'),
(26, '01', 'Universiti Malaya (UM)(PROGRAM USAHASAMA)', 'Diploma', 'images/institusi/universiti-malaya-um-1775627041.webp', 'Lot 25 Jalan Kaunselor, College Heights Garden Resort, 71700 Mantin, Negeri Sembilan', 'Program kerjasama bersama Universiti Malaya di bawah UIC merupakan satu inisiatif pendidikan yang memberi peluang kepada pelajar untuk mengikuti program diploma dengan sokongan serta kerjasama akademik daripada universiti terkemuka tersebut. Kerjasama ini bertujuan meningkatkan kualiti pembelajaran, memperkukuhkan kemahiran pelajar serta menyediakan pendidikan yang lebih berkualiti dan relevan dengan keperluan industri semasa.', '2026-04-07 13:44:01', '2026-05-18 15:14:56'),
(28, 'DK268(W)', 'IHM COLLEGE', 'Diploma', 'images/institusi/ihm-college-1775631032.jpg', '15, Jalan Raja Chulan, Bukit Bintang, 50200 Kuala Lumpur, Wilayah Persekutuan Kuala Lumpur', 'kolej swasta di Kuala Lumpur yang ditubuhkan pada tahun 1993 dan sebelum ini dikenali sebagai In-House Multimedia College. Kolej ini menawarkan pelbagai program seperti diploma dalam bidang multimedia, komunikasi massa dan sains komputer, dengan penekanan kepada kemahiran praktikal serta keperluan industri bagi menyediakan pelajar untuk dunia pekerjaan.', '2026-04-07 14:50:32', '2026-04-07 14:50:32'),
(29, 'L02922', 'MALAYSIA BUSINESS ACADEMY (MBA)', 'TVET', 'images/institusi/malaysia-business-academy-mba-1775633845.webp', 'No. 1-G, Jalan Putra Mahkota 7/8C, Putra Heights, 47650 Subang Jaya, Selangor, Malaysia', 'My Business Academy ialah sebuah pusat latihan kemahiran & pengembangan profesional di Malaysia, yang menawarkan kursus kemahiran, latihan industri dan program latihan kerjaya dalam bidang perniagaan, pendidikan awal, pemasaran dan pembangunan profesional. Ia beroperasi sebagai pembekal latihan yang diluluskan untuk kursus kemahiran (TVET)', '2026-04-07 15:37:25', '2026-04-07 15:37:25'),
(30, 'L02890', 'IMAN MOTORS ACADEMY', 'TVET', 'images/institusi/iman-motors-academy-1775634492.webp', 'Pusat komersial, 1280-1, Jalan Suriaman Biz 3, Persiaran Suriaman, 71950 Sendayan, Negeri Sembilan', 'Pusat latihan automotif yang menawarkan kursus praktikal dan TVET dalam penyelenggaraan kereta, mekanik, dan teknologi automotif untuk melahirkan tenaga kerja mahir bagi industri automotif.', '2026-04-07 15:48:12', '2026-04-07 15:48:12'),
(31, 'L02650', 'EAKON ACADEMY', 'TVET', 'images/institusi/eakon-academy-1775635111.webp', 'Lot 27737, Jalan 5/10 Bandar Rinching Seksyen 5, Semenyih, 43500 Selangor', 'Pusat latihan yang menawarkan kursus keusahawanan, pembangunan kemahiran profesional dan latihan vokasional, dengan fokus kepada latihan praktikal untuk meningkatkan kebolehan kerjaya dan keperluan industri.', '2026-04-07 15:58:31', '2026-04-07 15:59:53'),
(32, 'DK030(N)', 'MURNI INTERNATIONAL COLLEGE', 'SAINS KESIHATAN', 'images/institusi/murni-international-college-1775788625.jpg', 'PT. 12914, Jalan BBN 1/7f Persiaran Pusat Bandar Bandar Baru Nilai, 12910, Jalan BBN 1/7f, Bandar Baru Nilai, 71800 Nilai, Negeri Sembilan', 'Kolej Antaranbangsa Murni ditubuhkan pada 24 Ogos 2004 merupakan kolej pertama yang menawarkan program pengajian khusus dalam bidang Sains Kesihatan. Iltizam kolej ini adalah untuk melahirkan tenaga kerja kesihatan yang profesional.\r\n\r\nSetelah 22 tahun beroperasi, alumni Kolej Murni kini bekerja di Hospital-Hospital Kementerian Kesihatan Malaysia, Pusat Perubatan Universiti Malaya, Pusat Perubatan Prince Court, Hospital Columbia Asia, Hospital Gleneagles dan banyak lagi. Alumni Kolej Murni juga kini bekerja di Singapura, Indonesia, Arab Saudi dan Jerman.\r\n\r\nKolej ini terletak di tengah kemodenan bandar Nilai di Negeri Sembilan, Kolej Antarabangsa Murni menyediakan prasarana yang lengkap dengan jaringan akses kemudahan persekitaran mudah.\r\n\r\nBerdekatan dengan beberapa pusat membeli belah terkemuka, Balai Bomba, IPD Polis Nilai, Lapangan Terbang Antrabangsa Kuala Lumpur dan kompleks suka memberikan kehidupan di kampus lebih aktif.', '2026-04-09 10:37:05', '2026-05-18 16:10:29');
