(1, 'C-21-G', 'P854-009-4:2020S', 'images/institusi/whatsapp-image-2026-05-12-at-115123-am-1778571012.jpeg', '2026-05-11 15:30:12', '2026-05-11 15:30:12'),
(2, '70300', 'T982-001-3:2017 | T982-001-4:2018', 'images/institusi/whatsapp-image-2026-05-12-at-115123-am-1778632331.jpeg', '2026-05-12 08:32:11', '2026-05-12 08:32:11'),
