INSERT INTO `kursuses` (`id`, `kod_kursus`, `kod_institusi`, `nama_kursus`, `jenis_kursus`, `mod_pengajian`, `tempoh`, `kuota`, `tarikh_pendaftaran`, `penerangan`, `created_at`, `updated_at`) VALUES
(1, 'P854-009-4:2020S', 'C-21-G', 'PENDIDIKAN AWAL KANAK-KANAK (SINGLE TIER)', 'TAHAP 4 (SINGLE TIER)', 'SEPENUH MASA', '27 BULAN', 10, NULL, 'Latihan profesional dalam pengurusan tadika/prasekolah dan pengajaran pendidikan awal kanak-kanak.', '2026-04-07 11:13:45', '2026-06-25 00:37:09'),
(2, 'F432-005-2:2019 / F432-005-3:2019', '78000', 'PEMASANGAN & PENYELENGGARAAN ELEKTRIK', 'TAHAP 2/TAHAP 3', 'SEPENUH MASA', '12 BULAN / 12 BULAN', 10, NULL, 'Program Elektrik memberi fokus kepada kemahiran memasang, menyelenggara dan membaiki sistem pendawaian serta peralatan elektrik. Pelajar akan belajar asas litar elektrik, pendawaian domestik, penggunaan alat pengujian, pematuhan keselamatan dan standard kerja. Program ini melahirkan tenaga mahir yang mampu melakukan kerja pemasangan dan penyelenggaraan elektrik dengan selamat dan betul.', '2026-04-07 11:49:11', '2026-04-07 11:49:11'),
(3, 'HT-012-2:2012 / HT-012-3:2012', '71700 ', 'KULINARI', '-', 'SEPENUH MASA', '-', 10, NULL, 'Program Kulinari memberi latihan dalam kemahiran penyediaan makanan, teknik masakan, kawalan kebersihan, keselamatan dapur dan pengurusan asas dapur. Pelajar belajar memasak pelbagai hidangan, menyedia bahan, menghias makanan serta mematuhi standard kebersihan makanan. Program ini melahirkan tukang masak yang mahir, kreatif dan profesional untuk industri makanan dan perhotelan.', '2026-04-07 13:51:34', '2026-06-25 00:47:43'),
(4, 'IT-020-3:2013 / IT-020-4:2013', '71700 ', 'OPERASI SISTEM KOMPUTER', 'TAHAP 3 / TAHAP 4', 'SEPENUH MASA', '12 BULAN / 15 BULAN', 10, NULL, 'Program Sistem Komputer memberi fokus kepada kemahiran asas komputer dan teknologi maklumat, termasuk pemasangan, penyelenggaraan, pengendalian perkakasan, perisian dan rangkaian. Pelajar belajar troubleshoot masalah komputer, pengurusan data, serta memastikan sistem beroperasi dengan cekap dan selamat. Program ini melahirkan tenaga mahir dalam pengurusan dan sokongan sistem komputer.', '2026-04-07 13:53:36', '2026-04-07 13:53:36'),
(5, 'N821-001-3:2020', '71700 ', 'PENGURUSAN & PENTADBIRAN PEJABAT', '-', 'SEPENUH MASA', '-', 10, NULL, 'Program Pengurusan Pejabat memberi fokus kepada kemahiran pentadbiran pejabat termasuk pengurusan dokumen, komunikasi, penggunaan perisian pejabat, pengurusan mesyuarat dan penyelenggaraan rekod. Pelajar belajar mengurus operasi pejabat dengan cekap dan profesional. Program ini melahirkan tenaga mahir yang mampu menyokong operasi organisasi dengan teratur dan berkesan.', '2026-04-07 13:54:49', '2026-06-25 00:48:47'),
(6, 'MC-091-2:2013 / MC-091-3:2013 / MC-091-4:2013', 'C-21-G', 'PERKHIDMATAN KEJURUTERAAN AUTOMASI INDUSTRI (MEKATRONIK)', 'TAHAP 2 / TAHAP 3 / TAHAP 4', 'SEPENUH MASA', '2 TAHUN 9 BULAN', 10, NULL, 'Pelajar akan mempelajari pemasangan, pengujian, pengendalian dan penyelenggaraan sistem automasi seperti PLC, sensor, panel kawalan, motor, pneumatik dan hidraulik. Latihan menekankan gabungan teori dan amali, selaras keperluan industri sebenar bagi melahirkan tenaga kerja mahir yang kompeten, berdisiplin dan berdaya saing. Graduan berpeluang bekerja sebagai Juruteknik Automasi, Juruteknik Penyelenggaraan, Automation Engineer Support atau melanjutkan kerjaya ke tahap lebih tinggi dalam bidang automasi industri.', '2026-04-07 14:29:49', '2026-06-25 00:42:38'),
(7, '1561-005-2:2022 / 1561-005-3:2022', '47160', 'KULINARI', 'TAHAP 2 / TAHAP 3', 'SEPENUH MASA', '1 TAHUN 9 BULAN', 10, NULL, 'Program Kulinari memberi latihan dalam kemahiran penyediaan makanan, teknik masakan, kawalan kebersihan, keselamatan dapur dan pengurusan asas dapur. Pelajar belajar memasak pelbagai hidangan, menyedia bahan, menghias makanan serta mematuhi standard kebersihan makanan. Program ini melahirkan tukang masak yang mahir, kreatif dan profesional untuk industri makanan dan perhotelan.', '2026-04-07 14:36:14', '2026-06-25 00:49:35'),
(8, 'HT-014-2:2011 / HT-014-3:2011', '47160', 'PEMBUATAN PASTRI', 'TAHAP 2 / TAHAP 3', 'SEPENUH MASA', '1 TAHUN 6 BULAN', 10, NULL, 'Program Pembuatan Pastri memberi fokus kepada kemahiran menyediakan pelbagai pastri, kek dan manisan. Pelajar belajar teknik asas pastri seperti menguli, membakar, menghias, kawalan suhu, penyediaan krim dan doh, serta kebersihan dapur. Program ini melahirkan pembuat pastri yang mahir, kreatif dan mampu menghasilkan produk berkualiti mengikut standard industri.', '2026-04-07 14:38:57', '2026-06-25 00:49:50'),
(9, 'G452-002-2:2018 / G452-002-3:2018', 'L01143', 'AUTOMOTIF', 'TAHAP 3 / TAHAP 4', 'SEPENUH MASA', '17 BULAN', 10, NULL, 'Program ini memfokuskan kepada kemahiran asas automotif seperti servis dan baiki kenderaan. Pelajar belajar penyelenggaraan enjin, sistem brek, suspensi, elektrik asas dan keselamatan bengkel. Matlamatnya melahirkan individu yang mahir melakukan kerja servis asas, pemeriksaan dan pembaikan kenderaan ringan.', '2026-04-07 14:40:45', '2026-04-07 14:40:45'),
(10, 'MC-024-3:2012', 'L01143', 'PROSES KIMPALAN ARKA KEPINGAN LOGAM', 'TAHAP 3', 'SEPENUH MASA', '18 BULAN', 10, '2026-05-19', 'Program Kimpalan melatih pelajar dalam teknik mengimpal struktur logam menggunakan kaedah seperti SMAW, GTAW dan GMAW. Pelajar belajar membaca lukisan teknikal, menyediakan bahan, mengawal mesin kimpal serta mengutamakan keselamatan bengkel. Program ini melahirkan tenaga mahir yang mampu melakukan kerja fabrikasi dan penyambungan logam mengikut standard industri.', '2026-04-07 14:43:10', '2026-04-07 14:43:10'),
(11, 'S960-002-3:2020S', 'L01143', 'PERKHIDMATAN AUTOMASI INDUSTRI', 'TAHAP 2', 'SEPENUH MASA', '6 BULAN', 10, NULL, 'Program Automasi memberi fokus kepada penggunaan sistem kawalan, sensor, PLC, robotik dan mesin automatik dalam industri. Pelajar belajar memasang, menguji, menyelenggara dan menambah baik sistem automasi bagi meningkatkan kecekapan pengeluaran. Program ini melahirkan tenaga mahir yang mampu mengendalikan peralatan automasi moden dengan selamat dan profesional.', '2026-04-07 14:44:47', '2026-06-25 00:51:25'),
(12, 'HT-013-3-2011', 'L02138', 'PEMBUATAN ROTI (SINGLE TIER)', 'SINGLE TIER', 'SEPENUH MASA', '15 BULAN', 10, '2026-05-09', 'Program Pembuatan Roti memberi fokus kepada kemahiran menghasilkan pelbagai jenis roti, bun dan pastri asas. Pelajar belajar menyediakan doh, teknik menguli, proses penapaian, membakar dengan betul serta kawalan kualiti dan kebersihan dapur. Program ini melahirkan pembuat roti yang mahir, cekap dan memenuhi standard industri bakeri.', '2026-04-07 14:53:05', '2026-06-25 00:51:58'),
(13, 'HT-012-3-2012S', 'L02138', 'PENYEDIAAN & PENGELUARAN MAKANAN (SINGLE TIER)', 'SINGLE TIER', 'SEPENUH MASA', '12 BULAN', 10, NULL, 'Program Kulinari memberi latihan dalam kemahiran penyediaan makanan, teknik masakan, kawalan kebersihan, keselamatan dapur dan pengurusan asas dapur. Pelajar belajar memasak pelbagai hidangan, menyedia bahan, menghias makanan serta mematuhi standard kebersihan makanan. Program ini melahirkan tukang masak yang mahir, kreatif dan profesional untuk industri makanan dan perhotelan.', '2026-04-07 14:54:35', '2026-06-25 00:52:15'),
(14, 'F432-005-3-2019', 'L02138', 'PEMASANGAN & PENYELENGGARAAN ELEKTRIK (SINGLE TIER)', 'SINGLE TIER', 'SEPENUH MASA', '1 TAHUN 4 BULAN', 10, '2026-04-11', 'Program Elektrik memberi fokus kepada kemahiran memasang, menyelenggara dan membaiki sistem pendawaian serta peralatan elektrik. Pelajar akan belajar asas litar elektrik, pendawaian domestik, penggunaan alat pengujian, pematuhan keselamatan dan standard kerja. Program ini melahirkan tenaga mahir yang mampu melakukan kerja pemasangan dan penyelenggaraan elektrik dengan selamat dan betul.', '2026-04-07 14:56:00', '2026-06-25 00:54:26'),
(15, 'I561-005-3:2022S', 'L02138', 'OPERASI SENI KULINARI', 'SINGLE TIER', 'SEPENUH MASA', '17 BULAN', 10, '2026-04-11', 'Program Kulinari memberi latihan dalam kemahiran penyediaan makanan, teknik masakan, kawalan kebersihan, keselamatan dapur dan pengurusan asas dapur. Pelajar belajar memasak pelbagai hidangan, menyedia bahan, menghias makanan serta mematuhi standard kebersihan makanan. Program ini melahirkan tukang masak yang mahir, kreatif dan profesional untuk industri makanan dan perhotelan.', '2026-04-07 14:57:58', '2026-06-25 00:54:58'),
(16, 'S960-002-3:2020', 'L02138', 'PERKHIDMATAN ESTETIK (SINGLE TIER)', 'SINGLE TIER', 'SEPENUH MASA', '17 BULAN', 10, '2026-04-11', 'Program Kecantikan Estetik memberikan latihan dalam penjagaan kulit, rawatan wajah, asas dermatologi, penggunaan peralatan estetik, teknik spa serta penjagaan diri. Pelajar belajar melakukan rawatan kecantikan dengan kaedah yang selamat, profesional dan mengikut standard industri. Program ini melahirkan tenaga mahir dalam perkhidmatan kecantikan dan estetika moden.', '2026-04-07 15:00:48', '2026-06-25 00:55:15'),
(17, 'I561-005-2:2022 / I561-005-3:2022 / HT-012-4:2011', 'L02138', 'PENYEDIAAN & PENGELUARAN MAKANAN', 'TAHAP 2 / TAHAP 3 / TAHAP 4', 'SEPENUH MASA', '8 BULAN / 9 BULAN / 10 BULAN', 10, NULL, 'Program Kulinari memberi latihan dalam kemahiran penyediaan makanan, teknik masakan, kawalan kebersihan, keselamatan dapur dan pengurusan asas dapur. Pelajar belajar memasak pelbagai hidangan, menyedia bahan, menghias makanan serta mematuhi standard kebersihan makanan. Program ini melahirkan tukang masak yang mahir, kreatif dan profesional untuk industri makanan dan perhotelan.', '2026-04-07 15:02:22', '2026-06-25 00:55:31'),
(18, 'F432-005-2:2019 / F432-005-3:2019', 'L02138', 'PEMASANGAN & PENYELENGGARAAN ELEKTRIK', 'TAHAP 2 / TAHAP 3', 'SEPENUH MASA', '8 BULAN / 9 BULAN', 10, '2026-04-11', 'Program Elektrik memberi fokus kepada kemahiran memasang, menyelenggara dan membaiki sistem pendawaian serta peralatan elektrik. Pelajar akan belajar asas litar elektrik, pendawaian domestik, penggunaan alat pengujian, pematuhan keselamatan dan standard kerja. Program ini melahirkan tenaga mahir yang mampu melakukan kerja pemasangan dan penyelenggaraan elektrik dengan selamat dan betul.', '2026-04-07 15:04:27', '2026-04-07 15:04:27'),
(19, 'MC-024-3:2012', '42000', 'KIMPALAN', 'TAHAP 3', 'SEPENUH MASA', '18 BULAN', 10, '2026-05-19', 'Program ini memberikan kemahiran lanjutan dalam kimpalan arka logam menggunakan teknik shielded metal arc welding (SMAW). Pelajar akan mempelajari cara menyediakan bahan dan peralatan kimpalan, melaksanakan kimpalan pada pelbagai posisi dan jenis sambungan, mematuhi prosedur keselamatan industri, serta melakukan pemeriksaan dan penilaian kualiti hasil kimpalan.', '2026-04-07 15:18:04', '2026-04-07 15:18:04'),
(20, 'G452-002-2:2018 / G452-002-3:2018 / G452-002-4:2017', '42000', 'AUTOMOTIF', 'TAHAP 2 / TAHAP 3 / TAHAP 4', 'SEPENUH MASA', '12 BULAN / 12 BULAN / 15 BULAN', 10, NULL, 'Program ini memfokuskan kepada kemahiran asas automotif seperti servis dan baiki kenderaan. Pelajar belajar penyelenggaraan enjin, sistem brek, suspensi, elektrik asas dan keselamatan bengkel. Matlamatnya melahirkan individu yang mahir melakukan kerja servis asas, pemeriksaan dan pembaikan kenderaan ringan.', '2026-04-07 15:19:33', '2026-06-25 00:57:04'),
(21, 'F432-005-2:2019 / F432-005-3:2019 / F432-005-4:2019', '42000', 'ELEKTRIK', 'TAHAP 2 / TAHAP 3 / TAHAP 4', 'SEPENUH MASA', '12 BULAN / 12 BULAN / 18 BULAN', 10, NULL, 'Program Elektrik memberi fokus kepada kemahiran memasang, menyelenggara dan membaiki sistem pendawaian serta peralatan elektrik. Pelajar akan belajar asas litar elektrik, pendawaian domestik, penggunaan alat pengujian, pematuhan keselamatan dan standard kerja. Program ini melahirkan tenaga mahir yang mampu melakukan kerja pemasangan dan penyelenggaraan elektrik dengan selamat dan betul.', '2026-04-07 15:20:56', '2026-06-25 00:57:19'),
(22, 'S960-002-2:2020 / S960-002-3:2020 / S960-002-4:2020', '42000', 'PERKHIDMATAN KECANTIKAN', 'TAHAP 2 / TAHAP 3 / TAHAP 4', 'SEPENUH MASA', '6 BULAN / 6 BULAN / 12 BULAN', 10, NULL, 'Program Kecantikan Estetik memberikan latihan dalam penjagaan kulit, rawatan wajah, asas dermatologi, penggunaan peralatan estetik, teknik spa serta penjagaan diri. Pelajar belajar melakukan rawatan kecantikan dengan kaedah yang selamat, profesional dan mengikut standard industri. Program ini melahirkan tenaga mahir dalam perkhidmatan kecantikan dan estetika moden.', '2026-04-07 15:24:14', '2026-06-25 00:57:34'),
(23, 'IT-020-3:2013 / IT-020-4:2013', '42000', 'OPERASI SISTEM KOMPUTER', 'TAHAP 3 / TAHAP 4', 'SEPENUH MASA', '12 BULAN / 21 BULAN', 10, NULL, 'Program Sistem Komputer memberi fokus kepada kemahiran asas komputer dan teknologi maklumat, termasuk pemasangan, penyelenggaraan, pengendalian perkakasan, perisian dan rangkaian. Pelajar belajar troubleshoot masalah komputer, pengurusan data, serta memastikan sistem beroperasi dengan cekap dan selamat. Program ini melahirkan tenaga mahir dalam pengurusan dan sokongan sistem komputer.', '2026-04-07 15:25:19', '2026-04-07 15:25:19'),
(24, 'F432-005-2:2019 / F432-005-3:2019', 'L02238', 'ELEKTRIK & ELEKTRONIK', 'TAHAP 2 / TAHAP 3', 'SEPENUH MASA', '2 TAHUN', 10, NULL, 'Program ini menyediakan kemahiran asas dalam pemasangan, pendawaian dan penyelenggaraan sistem elektrik satu fasa di bangunan kediaman atau komersial kecil. Pelajar akan mempelajari pemasangan litar elektrik mengikut piawaian keselamatan, penyelenggaraan sistem elektrik termasuk pengesanan kerosakan dan pembaikan asas, serta amalan keselamatan kerja semasa bekerja dengan elektrik.', '2026-04-07 15:36:56', '2026-04-07 15:36:56'),
(25, 'ME-011-3:2014', 'L02238', 'OPERASI DAN PENYELENGGARAAN BOILER', 'TAHAP 3', 'SEPENUH MASA', '18 BULAN', 10, NULL, 'Program ini memberi latihan kemahiran dalam mengendalikan, memantau dan menyelenggara sistem boiler yang digunakan di industri seperti kilang, loji dan fasiliti komersial. Pelajar akan mempelajari asas operasi boiler, kawalan tekanan dan suhu, langkah keselamatan, prosedur permulaan dan penutupan boiler, pengesanan masalah, serta kerja penyelenggaraan berkala supaya sistem boiler sentiasa beroperasi dengan selamat, cekap dan mengikut piawaian industri.', '2026-04-07 15:38:03', '2026-06-25 00:59:36'),
(27, 'S960-002-1:2020/S960-002-2:2020', 'L02080', 'KECANTIKAN & PENJAGAAN PERIBADI', 'TAHAP 1 / TAHAP 2', 'SEPENUH MASA', '5 BULAN / 6 BULAN', 10, NULL, 'Program Kecantikan Estetik memberikan latihan dalam penjagaan kulit, rawatan wajah, asas dermatologi, penggunaan peralatan estetik, teknik spa serta penjagaan diri. Pelajar belajar melakukan rawatan kecantikan dengan kaedah yang selamat, profesional dan mengikut standard industri. Program ini melahirkan tenaga mahir dalam perkhidmatan kecantikan dan estetika moden.', '2026-04-07 16:18:15', '2026-06-25 00:50:31'),
(28, 'IT-0583:3:2012', 'L02080', 'REKABENTUK GRAFIK (DIGITAL)', 'TAHAP 2', 'SEPENUH MASA', '12 BULAN', 10, NULL, 'Program ini memberi pendedahan dan latihan dalam penghasilan reka bentuk visual menggunakan perisian digital. Pelajar akan belajar cara menghasilkan grafik seperti poster, logo, banner, media sosial, bahan promosi dan lain-lain menggunakan prinsip rekabentuk yang betul seperti warna, tipografi, komposisi dan kreativiti. Latihan turut merangkumi penggunaan perisian rekabentuk grafik, pengurusan fail digital serta keperluan asas industri kreatif supaya pelajar mampu menghasilkan hasil kerja yang kemas, menarik dan profesional.', '2026-04-07 16:19:18', '2026-06-25 00:51:11'),
(29, 'MC-024-3:2012', '144465-D', 'KIMPALAN', 'TAHAP 3', 'SEPENUH MASA', '18 BULAN', 10, '2026-05-19', 'Program Kimpalan melatih pelajar dalam teknik mengimpal struktur logam menggunakan kaedah seperti SMAW, GTAW dan GMAW. Pelajar belajar membaca lukisan teknikal, menyediakan bahan, mengawal mesin kimpal serta mengutamakan keselamatan bengkel. Program ini melahirkan tenaga mahir yang mampu melakukan kerja fabrikasi dan penyambungan logam mengikut standard industri.', '2026-04-07 16:29:38', '2026-04-07 16:29:38'),
(30, 'FB-025-3:2012', '144465-D', 'SETIAUSAHA KORPORAT', 'TAHAP 3', 'SEPENUH MASA', '1 TAHUN', 10, NULL, 'Program Setiausaha Korporat memberi fokus kepada kemahiran pentadbiran korporat, pengurusan dokumen rasmi, pematuhan undang-undang dan prosedur syarikat, serta komunikasi profesional. Pelajar belajar menyokong operasi organisasi, memastikan pentadbiran syarikat teratur dan mematuhi peraturan. Program ini melahirkan tenaga mahir yang cekap, teratur dan beretika dalam urusan korporat.', '2026-04-07 16:30:56', '2026-06-25 00:55:57'),
(31, 'IT-020-3:2013', '144465-D', 'RANGKAIAN KOMPUTER', 'TAHAP 3', 'SEPENUH MASA', '1 TAHUN', 10, NULL, 'Program Rangkaian Komputer memberi fokus kepada pemasangan, penyelenggaraan dan pengurusan rangkaian komputer. Pelajar belajar konfigurasi router dan switch, keselamatan rangkaian, troubleshooting serta pengurusan trafik data. Program ini melahirkan tenaga mahir yang mampu memastikan rangkaian beroperasi dengan cekap, selamat dan mengikut piawaian industri.', '2026-04-07 16:31:58', '2026-06-25 00:55:33'),
(32, 'F432-005-3:2019S', '144465-D', 'ELEKTRIK', 'TAHAP 3', 'SEPENUH MASA', '1 TAHUN 4 BULAN', 10, '2026-04-11', 'Program Elektrik memberi fokus kepada kemahiran memasang, menyelenggara dan membaiki sistem pendawaian serta peralatan elektrik. Pelajar akan belajar asas litar elektrik, pendawaian domestik, penggunaan alat pengujian, pematuhan keselamatan dan standard kerja. Program ini melahirkan tenaga mahir yang mampu melakukan kerja pemasangan dan penyelenggaraan elektrik dengan selamat dan betul.', '2026-04-07 16:33:10', '2026-04-07 16:33:10'),
(33, 'G452-002-2/3:2028', '144465-D', 'AUTOMOTIF', 'SINGLE TIER', 'SEPENUH MASA', '1 TAHUN 3 BULAN', 10, '2026-05-18', 'Kursus automotif ialah kursus yang memberi pendedahan kepada pelajar tentang penyelenggaraan, pemeriksaan dan pembaikan kenderaan. Pelajar akan belajar secara teori dan praktikal berkaitan enjin, sistem brek, transmisi, elektrik kenderaan, suspensi serta penggunaan peralatan bengkel. Kursus ini sesuai untuk mereka yang minat kerja hands-on, suka kenderaan dan ingin membina kemahiran dalam bidang teknikal. Selepas tamat pengajian, pelajar berpeluang bekerja sebagai juruteknik automotif, mekanik, penasihat servis atau menceburi industri berkaitan kenderaan', '2026-04-07 16:34:57', '2026-06-25 00:54:13'),
(34, '1561-005-2/3:2022', '144465-D', 'OPERASI SENI KULINARI', 'SINGLE TIER', 'SEPENUH MASA', '18 BULAN', 10, '2026-04-11', 'Memberi latihan dalam penyediaan dan pembuatan makanan, termasuk teknik memasak, kebersihan dan keselamatan makanan, kawalan kualiti hidangan serta pengurusan asas operasi dapur. Kursus ini sesuai untuk pelajar yang minat memasak dan ingin bekerja dalam bidang kulinari, katering, restoran atau hotel.', '2026-04-07 16:36:08', '2026-06-25 00:53:27'),
(35, 'G452-007-3:2019S', '144465-D', 'SERVIS KERETA ELEKTRIK & HIBRID (EV)', 'SINGLE TIER', 'SEPENUH MASA', '1 TAHUN 3 BULAN', 10, '2026-05-18', 'Kursus G452-007-3:2019S Servis Kereta Elektrik & Hibrid (EV) ialah latihan kemahiran untuk melahirkan juruteknik yang mampu melakukan pemeriksaan, diagnosis, servis dan pembaikan bagi kenderaan EV dan hibrid mengikut prosedur bengkel serta piawaian keselamatan voltan tinggi. Peserta akan didedahkan kepada kerja selamat sistem HV, penggunaan alat diagnostik seperti scan tool, serta servis komponen utama seperti bateri dan sistem pengecasan, motor elektrik, inverter/convertor, kabel voltan tinggi dan subsistem sokongan kenderaan. Selepas tamat kursus, peserta lebih bersedia untuk bekerja dalam bidang servis EV/Hybrid di pusat servis atau bengkel automotif, termasuk tugasan diagnostik dan penyelenggaraan sistem utama EV.', '2026-04-07 16:37:26', '2026-06-25 00:53:07'),
(36, 'F432-005-2:2019', '53100', 'PEMASANGAN & PENYELENGGARAAN ELEKTRIK', 'TAHAP 2 / TAHAP 3', 'SEPENUH MASA', '18 BULAN', 10, '2026-04-11', 'Program Pemasangan & Penyelenggaraan Elektrik direka untuk melatih pelajar dalam kemahiran teknikal pendawaian elektrik domestik dan industri. Melalui latihan amali yang intensif, pelajar akan menguasai teknik pemasangan sistem satu fasa dan tiga fasa, penyelenggaraan perkakas suis, serta pengujian litar mengikut piawaian Suruhanjaya Tenaga. Program ini menyediakan landasan kukuh bagi melahirkan teknisi yang kompeten untuk memenuhi keperluan sektor pembinaan dan fasiliti negara.', '2026-04-07 16:44:27', '2026-06-25 01:01:38'),
(37, '1561-002:2:2018', '53100', 'OPERASI SERVIS MAKANAN', 'TAHAP 2 / TAHAP 3', 'SEPENUH MASA', '1 TAHUN 9 BULAN', 10, NULL, 'Program Operasi Servis Makanan direka untuk melatih pelajar dalam kemahiran hospitaliti dan pengurusan restoran secara profesional. Melalui latihan amali yang intensif, pelajar akan menguasai teknik penyediaan ruang makan (Mise-en-place), gaya servis makanan (American, French, & Buffet), serta kemahiran layanan pelanggan yang berkualiti tinggi. Program ini memfokuskan kepada standard kebersihan dan keselamatan makanan (HACCP) bagi melahirkan tenaga kerja mahir yang kompeten untuk industri perhotelan dan katering.', '2026-04-07 16:45:34', '2026-06-25 01:01:49'),
(38, 'G452-002-3:2018', 'L02882', 'SERVIS KENDERAAN RINGAN - AUTOMOTIF (SINGLE TIER)', 'TAHAP 3', 'SEPENUH MASA', '21 BULAN', 10, NULL, 'Kursus ini memberi pengetahuan teori dan latihan praktikal tentang sistem utama kenderaan. Pelajar akan belajar bagaimana kenderaan berfungsi serta cara melakukan servis dan pembaikan dengan menggunakan peralatan bengkel. Latihan biasanya dijalankan di bengkel automotif, makmal latihan, dan latihan industri supaya pelajar mendapat pengalaman sebenar bekerja dengan kenderaan.', '2026-04-07 20:08:10', '2026-04-07 20:08:10'),
(39, 'G452-002-2:2018 / G452-002-3:2018', 'L02882', 'PERKHIDMATAN PEMBAIKAN – KENDERAAAN RINGAN (AUTOMOTIF)', 'SINGLE TIER', 'SEPENUH MASA', '2 TAHUN', 10, NULL, 'Program ini memfokuskan kepada kemahiran asas automotif seperti servis dan baiki kenderaan. Pelajar belajar penyelenggaraan enjin, sistem brek, suspensi, elektrik asas dan keselamatan bengkel. Matlamatnya melahirkan individu yang mahir melakukan kerja servis asas, pemeriksaan dan pembaikan kenderaan ringan.', '2026-04-07 20:09:21', '2026-04-07 20:09:21'),
(40, 'G452-002-2:2018 / G452-002-3:2018', 'L02163', 'AUTOMOTIF', '-', 'SEPENUH MASA', '-', 10, NULL, 'Program ini memfokuskan kepada kemahiran asas automotif seperti servis dan baiki kenderaan. Pelajar belajar penyelenggaraan enjin, sistem brek, suspensi, elektrik asas dan keselamatan bengkel. Matlamatnya melahirkan individu yang mahir melakukan kerja servis asas, pemeriksaan dan pembaikan kenderaan ringan.', '2026-04-07 20:16:18', '2026-04-07 20:16:18'),
(41, 'MC-091-2:2016 / MC-091-3:2016 / MC-091-4:2016', 'L02163', 'AUTOMASI INDUSTRI', 'TAHAP 2 / TAHAP 3 / TAHAP 4', 'SEPENUH MASA', '6 BULAN / 12 BULAN / 15 BULAN', 10, NULL, 'Program Automasi memberi fokus kepada penggunaan sistem kawalan, sensor, PLC, robotik dan mesin automatik dalam industri. Pelajar belajar memasang, menguji, menyelenggara dan menambah baik sistem automasi bagi meningkatkan kecekapan pengeluaran. Program ini melahirkan tenaga mahir yang mampu mengendalikan peralatan automasi moden dengan selamat dan profesional.', '2026-04-07 20:17:10', '2026-06-25 01:02:14'),
(42, 'T982-001-3:2017 | T982-001-4:2018', '70300', 'PENGURUSAN PENJAGAAN DAN PENDIDIKAN KANAK-KANAK AWAL', 'TAHAP 3 / TAHAP 4', 'SEPENUH MASA', '27 BULAN', 10, '2026-04-03', 'Program ini memberi fokus kepada kemahiran mengasuh, mendidik dan mengurus perkembangan awal kanak-kanak dari segi kognitif, sosial, emosi dan fizikal. Pelajar belajar perancangan aktiviti pembelajaran, keselamatan dan kesihatan kanak-kanak, komunikasi berkesan serta pengurusan pusat asuhan. Program ini melahirkan pengasuh dan pendidik awal kanak-kanak yang profesional, penyayang dan beretika.', '2026-04-07 20:22:25', '2026-06-25 00:57:37'),
(43, '1561-005-3:2022', '70300', 'OPERASI SENI KULINARI', 'TAHAP 2 / TAHAP 3', 'SEPENUH MASA', '18 BULAN', 10, '2026-04-11', 'Program Kulinari memberi latihan dalam kemahiran penyediaan makanan, teknik masakan, kawalan kebersihan, keselamatan dapur dan pengurusan asas dapur. Pelajar belajar memasak pelbagai hidangan, menyedia bahan, menghias makanan serta mematuhi standard kebersihan makanan. Program ini melahirkan tukang masak yang mahir, kreatif dan profesional untuk industri makanan dan perhotelan.', '2026-04-07 20:23:42', '2026-04-07 20:23:42'),
(44, 'MC-024-3:2012', 'P13A-1', 'KIMPALAN', 'TAHAP 3', 'SEPENUH MASA', '18 BULAN', 10, NULL, 'Program Kimpalan melatih pelajar dalam teknik mengimpal struktur logam menggunakan kaedah seperti SMAW, GTAW dan GMAW. Pelajar belajar membaca lukisan teknikal, menyediakan bahan, mengawal mesin kimpal serta mengutamakan keselamatan bengkel. Program ini melahirkan tenaga mahir yang mampu melakukan kerja fabrikasi dan penyambungan logam mengikut standard industri.', '2026-04-07 20:29:12', '2026-05-05 19:39:00'),
(45, 'G452-002-3:2018-S', 'P13A-1', 'AUTOMOTIF', 'SINGLE TIER', 'SEPENUH MASA', '24 BULAN', 10, NULL, 'Program ini memfokuskan kepada kemahiran asas automotif seperti servis dan baiki kenderaan. Pelajar belajar penyelenggaraan enjin, sistem brek, suspensi, elektrik asas dan keselamatan bengkel. Matlamatnya melahirkan individu yang mahir melakukan kerja servis asas, pemeriksaan dan pembaikan kenderaan ringan.', '2026-04-07 20:30:18', '2026-06-25 01:01:00'),
(46, 'F432-005-3-2019S', 'P13A-1', 'ELEKTRIK', 'TAHAP 2 / TAHAP 3 (ST)', 'SEPENUH MASA', '16 BULAN', 10, NULL, 'Program Elektrik memberi fokus kepada kemahiran memasang, menyelenggara dan membaiki sistem pendawaian serta peralatan elektrik. Pelajar akan belajar asas litar elektrik, pendawaian domestik, penggunaan alat pengujian, pematuhan keselamatan dan standard kerja. Program ini melahirkan tenaga mahir yang mampu melakukan kerja pemasangan dan penyelenggaraan elektrik dengan selamat dan betul.', '2026-04-07 20:31:27', '2026-04-07 20:31:27'),
(47, 'MC-024-3:2012', '28600', 'KIMPALAN', 'TAHAP 3', 'SEPENUH MASA', '18 BULAN', 10, NULL, 'Program Kimpalan melatih pelajar dalam teknik mengimpal struktur logam menggunakan kaedah seperti SMAW, GTAW dan GMAW. Pelajar belajar membaca lukisan teknikal, menyediakan bahan, mengawal mesin kimpal serta mengutamakan keselamatan bengkel. Program ini melahirkan tenaga mahir yang mampu melakukan kerja fabrikasi dan penyambungan logam mengikut standard industri.', '2026-04-07 20:35:33', '2026-04-07 20:35:33'),
(48, 'ET-012-3:2012', '28600', 'PENTADBIRAN PRA SEKOLAH', 'TAHAP 3 / TAHAP 4', 'SEPENUH MASA', '2 TAHUN', 10, NULL, 'Pentadbiran Pra Sekolah ialah kursus yang memberi pendedahan tentang pengurusan, pentadbiran dan pendidikan awal kanak-kanak di peringkat prasekolah atau tadika. Kursus ini bertujuan melatih pelajar supaya memahami cara mengurus operasi prasekolah serta membimbing perkembangan kanak-kanak secara menyeluruh. Dalam kursus ini, pelajar akan mempelajari asas pendidikan awal kanak-kanak, teknik pengajaran yang sesuai, serta cara mengurus aktiviti pembelajaran yang menyeronokkan dan berkesan untuk kanak-kanak.', '2026-04-07 20:36:43', '2026-06-25 00:59:27'),
(49, 'G452-002-3:2018S', '28600', 'AUTOMOTIF', 'TAHAP 2 / TAHAP 3 (ST)', 'SEPENUH MASA', '2 TAHUN', 10, NULL, 'Program ini memfokuskan kepada kemahiran asas automotif seperti servis dan baiki kenderaan. Pelajar belajar penyelenggaraan enjin, sistem brek, suspensi, elektrik asas dan keselamatan bengkel. Matlamatnya melahirkan individu yang mahir melakukan kerja servis asas, pemeriksaan dan pembaikan kenderaan ringan.', '2026-04-07 20:37:59', '2026-06-25 00:59:41'),
(50, 'F432-005-3:2019S', '28600', 'ELEKTRIK', 'TAHAP 2 / TAHAP 3 (ST)', 'SEPENUH MASA', '16 BULAN', 10, NULL, 'Program Elektrik memberi fokus kepada kemahiran memasang, menyelenggara dan membaiki sistem pendawaian serta peralatan elektrik. Pelajar akan belajar asas litar elektrik, pendawaian domestik, penggunaan alat pengujian, pematuhan keselamatan dan standard kerja. Program ini melahirkan tenaga mahir yang mampu melakukan kerja pemasangan dan penyelenggaraan elektrik dengan selamat dan betul.', '2026-04-07 20:39:09', '2026-04-07 20:39:09'),
(51, '7982-001-3:2017', '28600', 'PENDIDIKAN AWAL KANAK-KANAK', 'TAHAP 3', 'SEPENUH MASA', '1 TAHUN', 10, '2026-04-03', 'Program ini memberi fokus kepada kemahiran mengasuh, mendidik dan mengurus perkembangan awal kanak-kanak dari segi kognitif, sosial, emosi dan fizikal. Pelajar belajar perancangan aktiviti pembelajaran, keselamatan dan kesihatan kanak-kanak, komunikasi berkesan serta pengurusan pusat asuhan. Program ini melahirkan pengasuh dan pendidik awal kanak-kanak yang profesional, penyayang dan beretika.', '2026-04-07 20:40:17', '2026-06-25 01:00:05'),
(52, 'MC-024-3:2022', 'P13A', 'KIMPALAN', 'TAHAP 3', 'SEPENUH MASA', '18 BULAN', 10, NULL, 'Program Kimpalan melatih pelajar dalam teknik mengimpal struktur logam menggunakan kaedah seperti SMAW, GTAW dan GMAW. Pelajar belajar membaca lukisan teknikal, menyediakan bahan, mengawal mesin kimpal serta mengutamakan keselamatan bengkel. Program ini melahirkan tenaga mahir yang mampu melakukan kerja fabrikasi dan penyambungan logam mengikut standard industri', '2026-04-07 20:50:36', '2026-06-25 00:57:54'),
(53, 'I561-005-3:2022', 'P13A', 'OPERASI SENI KULINARI', 'TAHAP 2 / TAHAP 3 (ST)', 'SEPENUH MASA', '18 BULAN', 10, '2026-04-11', 'Program Kulinari memberi latihan dalam kemahiran penyediaan makanan, teknik masakan, kawalan kebersihan, keselamatan dapur dan pengurusan asas dapur. Pelajar belajar memasak pelbagai hidangan, menyedia bahan, menghias makanan serta mematuhi standard kebersihan makanan. Program ini melahirkan tukang masak yang mahir, kreatif dan profesional untuk industri makanan dan perhotelan.', '2026-04-07 20:51:32', '2026-06-25 00:58:12'),
(54, 'F432-005-3-2019S', 'P13A', 'ELEKTRIK', 'TAHAP 2 / TAHAP 3 (ST)', 'SEPENUH MASA', '16 BULAN', 10, NULL, 'Program Elektrik memberi fokus kepada kemahiran memasang, menyelenggara dan membaiki sistem pendawaian serta peralatan elektrik. Pelajar akan belajar asas litar elektrik, pendawaian domestik, penggunaan alat pengujian, pematuhan keselamatan dan standard kerja. Program ini melahirkan tenaga mahir yang mampu melakukan kerja pemasangan dan penyelenggaraan elektrik dengan selamat dan betul.', '2026-04-07 20:52:28', '2026-04-07 20:52:28'),
(55, 'T982-001-3:2017', 'L02054', 'PENDIDIKAN AWAL KANAK-KANAK', 'TAHAP 3', 'SEPENUH MASA', '12 BULAN', 10, '2026-04-03', 'Program ini memberi fokus kepada kemahiran mengasuh, mendidik dan mengurus perkembangan awal kanak-kanak dari segi kognitif, sosial, emosi dan fizikal. Pelajar belajar perancangan aktiviti pembelajaran, keselamatan dan kesihatan kanak-kanak, komunikasi berkesan serta pengurusan pusat asuhan. Program ini melahirkan pengasuh dan pendidik awal kanak-kanak yang profesional, penyayang dan beretika.', '2026-04-07 20:58:30', '2026-04-07 20:58:30'),
(56, 'PERKHIDMATAN DALAM PENERBANGAN', 'TP-060-3:2013', 'PERKHIDMATAN DALAM PENERBANGAN', '-', 'SEPENUH MASA', '-', 10, NULL, 'Program Inflight Services memberi fokus kepada kemahiran layanan penumpang, keselamatan kabin, pengurusan makanan dan minuman, komunikasi berkesan serta prosedur kecemasan di dalam penerbangan. Pelajar dilatih untuk menjadi kru kabin profesional yang ramah, cekap dan memastikan pengalaman penerbangan selesa dan selamat.', '2026-04-07 21:09:26', '2026-06-25 00:56:40'),
(57, 'TP-060-4:2013', 'TP-060-3:2013', 'PENYELENGGARAAN PESAWAT', '-', 'SEPENUH MASA', '-', 10, NULL, 'Program Aircraft Maintenance memberi fokus kepada penyelenggaraan dan pembaikan pesawat. Pelajar belajar memeriksa enjin, sistem hidraulik, elektrik, avionik dan struktur pesawat, serta mematuhi prosedur keselamatan dan standard penerbangan. Program ini melahirkan tenaga mahir yang mampu memastikan pesawat beroperasi dengan selamat dan cekap mengikut piawaian industri penerbangan.', '2026-04-07 21:10:20', '2026-06-25 00:56:52'),
(58, 'T982-001-3:2017', '47650', 'PENGURUSAN AWAL KANAK-KANAK', 'TAHAP 3', 'SEPENUH MASA', '1 TAHUN', 10, '2026-04-03', 'Program ini memberi fokus kepada kemahiran mengasuh, mendidik dan mengurus perkembangan awal kanak-kanak dari segi kognitif, sosial, emosi dan fizikal. Pelajar belajar perancangan aktiviti pembelajaran, keselamatan dan kesihatan kanak-kanak, komunikasi berkesan serta pengurusan pusat asuhan. Program ini melahirkan pengasuh dan pendidik awal kanak-kanak yang profesional, penyayang dan beretika.', '2026-04-07 21:18:05', '2026-04-07 21:18:05'),
(59, '1561-005-3:2022', 'L02723', 'OPERASI SENI KULINARI', 'TAHAP 2 / TAHAP 3 (ST)', 'SEPENUH MASA', '2 TAHUN', 10, '2026-04-11', 'Program Kulinari memberi latihan dalam kemahiran penyediaan makanan, teknik masakan, kawalan kebersihan, keselamatan dapur dan pengurusan asas dapur. Pelajar belajar memasak pelbagai hidangan, menyedia bahan, menghias makanan serta mematuhi standard kebersihan makanan. Program ini melahirkan tukang masak yang mahir, kreatif dan profesional untuk industri makanan dan perhotelan.', '2026-04-07 21:27:37', '2026-05-15 08:54:57'),
(60, 'N821-001-3:2020 / FB-025-4:2012', 'L02723', 'PENGURUSAN PEJABAT', '-', 'SEPENUH MASA', '-', 10, NULL, 'Program Pengurusan Pejabat memberi fokus kepada kemahiran pentadbiran pejabat termasuk pengurusan dokumen, komunikasi, penggunaan perisian pejabat, pengurusan mesyuarat dan penyelenggaraan rekod. Pelajar belajar mengurus operasi pejabat dengan cekap dan profesional. Program ini melahirkan tenaga mahir yang mampu menyokong operasi organisasi dengan teratur dan berkesan.', '2026-04-07 21:28:47', '2026-06-25 00:54:25'),
(61, 'HT-041-2:2011 / HT-041-3:2011', 'L02723', 'PEMBUATAN PASTRI', '-', 'SEPENUH MASA', '-', 10, NULL, 'Program Pembuatan Pastri memberi fokus kepada kemahiran menyediakan pelbagai pastri, kek dan manisan. Pelajar belajar teknik asas pastri seperti menguli, membakar, menghias, kawalan suhu, penyediaan krim dan doh, serta kebersihan dapur. Program ini melahirkan pembuat pastri yang mahir, kreatif dan mampu menghasilkan produk berkualiti mengikut standard industri.', '2026-04-07 21:29:53', '2026-06-25 00:54:37'),
(62, 'G452-002-3:2018', 'L02723', 'AUTOMOTIF', 'TAHAP 3 / TAHAP 4 (ST)', 'SEPENUH MASA', '2 TAHUN', 10, NULL, 'Program ini memfokuskan kepada kemahiran asas automotif seperti servis dan baiki kenderaan. Pelajar belajar penyelenggaraan enjin, sistem brek, suspensi, elektrik asas dan keselamatan bengkel. Matlamatnya melahirkan individu yang mahir melakukan kerja servis asas, pemeriksaan dan pembaikan kenderaan ringan.', '2026-04-07 21:30:42', '2026-04-07 21:30:42'),
(63, 'T982-001-3:2017 / T982-001-4:2018', 'L02723', 'PENGURUSAN AWAL KANAK-KANAK', 'TAHAP 3 / TAHAP 4 (ST)', 'SEPENUH MASA', '27 BULAN', 10, NULL, 'Program ini memberi fokus kepada kemahiran mengasuh, mendidik dan mengurus perkembangan awal kanak-kanak dari segi kognitif, sosial, emosi dan fizikal. Pelajar belajar perancangan aktiviti pembelajaran, keselamatan dan kesihatan kanak-kanak, komunikasi berkesan serta pengurusan pusat asuhan. Program ini melahirkan pengasuh dan pendidik awal kanak-kanak yang profesional, penyayang dan beretika.', '2026-04-07 21:31:51', '2026-06-25 00:55:11'),
(64, 'DSI/(R2/221/4/0052)( 8/2027)( MQA/FA1693)', 'L02313', 'DIPLOMA SYARIAH ISLAMIAH', 'Diploma', 'SEPENUH MASA', '3 TAHUN', 10, NULL, 'Program Diploma Syariah Islamiah memberi pengetahuan tentang hukum-hukum Islam berdasarkan Al-Quran dan Hadis. Kursus ini merangkumi bidang seperti fiqh, akidah, ibadah, muamalat serta undang-undang Islam bagi melahirkan pelajar yang memahami dan mampu mengamalkan syariah dalam kehidupan serta kerjaya.', '2026-04-07 11:59:12', '2026-06-25 00:40:15'),
(65, 'DEC/(R2/0112/4/0018)( 2/2029) (MQA/FA2298)', 'L02313', 'DIPLOMA PENDIDIKAN AWAL KANAK-KANAK', 'Diploma', 'SEPENUH MASA', '3 TAHUN', 10, NULL, 'Program Diploma Pendidikan Awal Kanak-Kanak memberi pengetahuan dan kemahiran dalam perkembangan serta pendidikan kanak-kanak dari usia awal. Kursus ini merangkumi aspek penjagaan, psikologi kanak-kanak, kaedah pengajaran dan aktiviti pembelajaran untuk melatih pelajar menjadi pendidik atau penjaga kanak-kanak yang profesional.', '2026-04-07 13:07:25', '2026-06-25 00:40:50'),
(66, 'DDWG/(R2/345/4/0183)( 5/2027)( MQA/FA2192)', '05', 'DIPLOMA PENGURUSAN TEKNOLOGI MAKLUMAT', 'Diploma', 'SEPENUH MASA', '3 TAHUN', 10, NULL, 'Program Diploma Pengurusan Teknologi Maklumat memberi pengetahuan tentang penggunaan teknologi dalam pengurusan sistem dan organisasi. Kursus ini merangkumi asas pengaturcaraan, pangkalan data, rangkaian komputer serta pengurusan sistem maklumat untuk melatih pelajar mengurus dan menyokong keperluan teknologi dalam sesebuah organisasi.', '2026-04-07 13:11:52', '2026-06-25 00:41:38'),
(67, 'DDWF/(R2/341/4/0018)( 05/2027)( MQA/ FA2191)', '05', 'DIPLOMA PENGURUSAN HARTANAH', 'Diploma', 'SEPENUH MASA', '3 TAHUN', 10, NULL, 'Program Diploma Pengurusan Hartanah memberi pengetahuan tentang pengurusan, penilaian dan pentadbiran hartanah seperti rumah, bangunan dan tanah. Kursus ini merangkumi aspek perundangan hartanah, penilaian aset, pengurusan sewaan serta pembangunan hartanah bagi melatih pelajar dalam bidang pengurusan hartanah secara profesional.', '2026-04-07 13:15:10', '2026-06-25 00:41:58'),
(68, 'BA111/(R2/340/4/0396)( 10/2024)( A1569)', 'UE4344001', 'DIPLOMA PENGAJIAN PERNIAGAAN', 'Diploma', 'SEPENUH MASA', '2.5 TAHUN', 10, NULL, 'Program Diploma Pengajian Perniagaan memberi pengetahuan asas tentang dunia perniagaan dan pengurusan. Kursus ini merangkumi bidang seperti pemasaran, kewangan, ekonomi, pengurusan organisasi dan keusahawanan bagi melatih pelajar memahami operasi serta fungsi sesebuah perniagaan.', '2026-04-07 13:19:08', '2026-06-25 00:42:25'),
(69, 'AC110/(R2/344/4/0241)( 10/2024)( A1570)', 'UE4344001', 'DIPLOMA PERAKAUNAN', 'Diploma', 'SEPENUH MASA', '3 TAHUN', 10, NULL, 'Program Diploma Perakaunan memberi pengetahuan dan kemahiran dalam merekod, menganalisis dan menyediakan penyata kewangan. Kursus ini merangkumi asas perakaunan, percukaian, audit serta pengurusan kewangan untuk melatih pelajar dalam mengurus rekod kewangan organisasi dengan tepat dan sistematik.', '2026-04-07 13:26:34', '2026-06-25 00:42:48'),
(70, 'BA003', 'UE4344001', 'PRA DIPLOMA PERDAGANGAN', 'Diploma', 'SEPENUH MASA', '6 BULAN', 10, NULL, 'Program Pra Diploma Perdagangan ialah program asas yang menyediakan pelajar sebelum melanjutkan pengajian ke peringkat diploma dalam bidang perniagaan. Kursus ini memberi pendedahan awal kepada subjek seperti asas perniagaan, matematik, bahasa dan kemahiran belajar bagi membantu pelajar bersedia untuk pengajian di peringkat yang lebih tinggi.', '2026-04-07 13:30:45', '2026-06-25 00:43:05'),
(71, 'MQA/SWA0628', '01', 'DIPLOMA PENGURUSAN', 'Diploma', 'SEPENUH MASA', '3 TAHUN', 10, NULL, 'Program Diploma Pengurusan memberi pengetahuan asas dalam bidang pengurusan organisasi seperti perniagaan, pentadbiran, kewangan dan sumber manusia. Kursus ini melatih pelajar dalam kemahiran pengurusan, komunikasi dan membuat keputusan untuk menyediakan mereka kepada kerjaya dalam sektor awam mahupun swasta.', '2026-04-07 13:51:33', '2026-06-25 00:43:56'),
(72, 'MQA/SWA0630', '01', 'DIPLOMA PENGURUSAN SUMBER MANUSIA', 'Diploma', 'SEPENUH MASA', '3 TAHUN', 10, NULL, 'Program Diploma Pengurusan Sumber Manusia memberi pengetahuan tentang pengurusan pekerja dalam sesebuah organisasi. Kursus ini merangkumi aspek pengambilan pekerja, latihan, pentadbiran gaji, hubungan industri serta pembangunan tenaga kerja bagi memastikan pengurusan sumber manusia yang efektif dalam organisasi.', '2026-04-07 13:52:39', '2026-06-25 00:44:28'),
(73, 'MQA/SWA0629', '01', 'DIPLOMA PENGURUSAN PERNIAGAAN', 'Diploma', 'SEPENUH MASA', '3 TAHUN', 10, NULL, 'Program Diploma Pengurusan Perniagaan memberi pengetahuan asas dalam bidang perniagaan seperti pengurusan, pemasaran, kewangan dan keusahawanan. Kursus ini melatih pelajar dengan kemahiran mengurus operasi perniagaan serta membuat keputusan untuk mempersiapkan mereka dalam dunia pekerjaan atau menjadi usahawan.', '2026-04-07 13:53:46', '2026-06-25 00:44:41'),
(76, 'R2/213/4/0359 (MQA/A6023)', 'DK268(W)', 'DIPLOMA REKA BENTUK MULTIMEDIA', 'Diploma', 'SEPENUH MASA', '3 TAHUN', 10, NULL, 'Program Diploma Reka Bentuk Multimedia memberi pengetahuan dan kemahiran dalam menghasilkan kandungan kreatif digital seperti grafik, animasi, video dan reka bentuk laman web. Kursus ini menggabungkan elemen seni, kreativiti dan teknologi untuk melatih pelajar menjadi profesional dalam industri multimedia dan media digital.', '2026-04-07 14:54:18', '2026-06-25 00:45:12'),
(77, '(R/321/4/0029) – MQA/FA0611', 'DK268(W)', 'DIPLOMA KOMUNIKASI MASSA', 'Diploma', 'SEPENUH MASA', '3 TAHUN', 10, NULL, 'Program Diploma Komunikasi Massa memberi pengetahuan tentang bidang media dan komunikasi seperti kewartawanan, penyiaran, perhubungan awam dan media digital. Kursus ini melatih pelajar dalam kemahiran menulis, penyuntingan, penghasilan kandungan serta pengurusan media untuk industri komunikasi moden.', '2026-04-07 14:59:20', '2026-06-25 00:45:28'),
(78, 'R2/861/4/0003 – MQA/FA10855', 'DK268(W)', 'DIPLOMA PENGURUSAN KESELAMATAN & PENGUATKUASAAN UNDANG-UNDANG', 'Diploma', 'SEPENUH MASA', '3 TAHUN', 10, NULL, 'Program Diploma Pengurusan Keselamatan & Penguatkuasaan Undang-Undang memberi pengetahuan dan kemahiran dalam bidang keselamatan, penguatkuasaan serta sistem undang-undang. Kursus ini merangkumi aspek pengurusan keselamatan, pencegahan jenayah, operasi penguatkuasaan dan undang-undang asas bagi melahirkan graduan yang berkemahiran dalam sektor keselamatan dan agensi penguatkuasaan.', '2026-04-07 15:04:04', '2026-06-25 00:45:45'),
(79, 'T982-001-3:2017 (Tahap 3) / T982-001-4:2018 (Tahap 4)', 'L02922', 'PENJAGAAN & PENDIDIKAN AWAL KANAK-KANAK', 'TVET', 'SEPENUH MASA', '2 TAHUN', 10, NULL, 'KEMUDAHAN FASILITI', '2026-04-07 15:40:38', '2026-06-25 00:52:11'),
(80, 'K12001/G452-002-4:2017-ST-A', 'L02890', 'TEKNOLOGI AUTOMOTIF', 'TVET', 'SEPENUH MASA', '2 TAHUN', 10, NULL, 'KEMUDAHAN FASILITI', '2026-04-07 15:50:59', '2026-06-25 00:51:48'),
(81, 'S960-002-2:2020', 'L02650', 'PENYAMANAN UDARA & PENYEJUKAN (HVAC)', 'TVET', 'SEPENUH MASA', '2 TAHUN', 10, NULL, 'KEMUDAHAN FASILITI', '2026-04-07 16:15:47', '2026-06-25 00:51:20'),
(82, '(R3/0913/4/00560)(10,29)(MQA/FA5362)', 'DK030(N)', 'DIPLOMA KEJURURAWATAN', 'SAINS KESIHATAN', 'SEPENUH MASA', '3 TAHUN', 10, NULL, 'Program Diploma Kejururawatan melatih pelajar menjadi jururawat profesional yang mahir dalam penjagaan pesakit. Kursus ini merangkumi pengetahuan tentang penjagaan kesihatan, rawatan pesakit, kemahiran klinikal serta latihan praktikal di hospital atau pusat kesihatan. Graduan program ini boleh bekerja sebagai jururawat di hospital, klinik dan institusi kesihatan.', '2026-04-09 10:51:38', '2026-06-25 00:46:13'),
(83, '(R3/0913/4/0057)03,30)(MQA/FA8746)', 'DK030(N)', 'DIPLOMA SAINS PERUBATAN DAN KESIHATAN', 'SAINS KESIHATAN', 'SEPENUH MASA', '3 TAHUN', 10, NULL, 'Program Diploma Sains Perubatan dan Kesihatan memberi pengetahuan asas tentang bidang perubatan dan kesihatan. Kursus ini merangkumi topik seperti asas sains perubatan, penjagaan kesihatan, anatomi dan fisiologi manusia serta kemahiran asas yang berkaitan dengan perkhidmatan kesihatan.', '2026-04-09 10:59:38', '2026-06-25 00:46:27'),
(84, '(R2/0414/4/044)(8,28)(MQA/FA3436)', 'DK030(N)', 'DIPLOMA PENGURUSAN PENJAGAAN KESIHATAN', 'SAINS KESIHATAN', 'SEPENUH MASA', '3 TAHUN', 10, NULL, 'Program Diploma Pengurusan Penjagaan Kesihatan memberi pengetahuan dan kemahiran dalam pengurusan perkhidmatan kesihatan seperti hospital, klinik dan pusat perubatan. Kursus ini merangkumi aspek pentadbiran kesihatan, pengurusan operasi, perkhidmatan pesakit serta sistem pengurusan dalam sektor penjagaan kesihatan.', '2026-04-09 11:13:44', '2026-06-25 00:46:40'),
(85, '(N/0414/4/0018)(06/27)(MQA/FA15689)', 'DK030(N)', 'DIPLOMA PENGURUSAN INDUSTRI HALAL', 'SAINS KESIHATAN', 'SEPENUH MASA', '3 TAHUN', 10, NULL, 'Program Diploma Pengurusan Industri Halal memberi pengetahuan tentang pengurusan, operasi dan piawaian dalam industri halal. Kursus ini meliputi aspek seperti pensijilan halal, pengurusan produk halal, kawalan kualiti serta pengurusan perniagaan yang mematuhi prinsip syariah bagi memenuhi keperluan pasaran halal.', '2026-04-09 11:17:13', '2026-06-25 00:46:57'),
(86, 'JPT-DK030(N)', 'DK030(N)', 'SIJIL PEMBANTU PENJAGAAN PESAKIT', 'SAINS KESIHATAN', 'SEPENUH MASA', '3 TAHUN', 10, NULL, 'Program Sijil Pembantu Penjagaan Pesakit merupakan kursus yang melatih pelajar untuk membantu dalam penjagaan pesakit di hospital, klinik atau pusat penjagaan kesihatan. Kursus ini memberi pengetahuan asas tentang penjagaan pesakit, kebersihan diri pesakit, bantuan pergerakan pesakit serta sokongan kepada jururawat dan kakitangan perubatan dalam memastikan keselesaan dan keselamatan pesakit.', '2026-04-09 11:20:02', '2026-06-25 00:47:27'),
(87, '(MQA/PA16868) (N/0913/2/0018)', 'DK030(N)', 'POST BASIC IN RENAL CARE NURSING', 'SAINS KESIHATAN', 'SEPENUH MASA', '3 TAHUN', 10, NULL, 'Program Post Basic in Renal Care Nursing merupakan kursus lanjutan untuk jururawat yang memberi pengetahuan dan kemahiran khusus dalam penjagaan pesakit yang mengalami penyakit buah pinggang. Kursus ini memberi tumpuan kepada rawatan seperti dialisis, pemantauan pesakit renal serta pengurusan penjagaan kesihatan bagi pesakit yang mengalami kegagalan buah pinggang.', '2026-04-09 11:28:18', '2026-06-25 00:47:42');
